-- Step 1: Extend products table with new fields
ALTER TABLE public.products
ADD COLUMN IF NOT EXISTS featured BOOLEAN DEFAULT FALSE,
ADD COLUMN IF NOT EXISTS form_type TEXT DEFAULT 'Capsules',
ADD COLUMN IF NOT EXISTS quantity_spec TEXT,
ADD COLUMN IF NOT EXISTS ingredients TEXT[] DEFAULT '{}',
ADD COLUMN IF NOT EXISTS seo_tags TEXT[] DEFAULT '{}',
ADD COLUMN IF NOT EXISTS storage_instructions TEXT,
ADD COLUMN IF NOT EXISTS dosage_instructions TEXT,
ADD COLUMN IF NOT EXISTS disclaimer TEXT;

-- Step 2: Clear existing products and kits (handle foreign keys)
DELETE FROM public.order_items WHERE product_id IN (SELECT id FROM public.products);
DELETE FROM public.products WHERE TRUE;
DELETE FROM public.health_kits WHERE TRUE;

